// setTimeout nümunəsi
function sayHello(name) {
  console.log('Salam, ' + name);
}

setTimeout(sayHello, 2000, 'Ali'); // 2 saniyə sonra: Salam, Ali

// setInterval nümunəsi
function showTime() {
  const time = new Date().toLocaleTimeString();
  console.log('Cari vaxt: ' + time);
}

setInterval(showTime, 1000); // Hər saniyə vaxtı göstərir

// setInterval-in dayandırılması
function count() {
  console.log('Hesablama...');
}

const intervalId = setInterval(count, 1000);
setTimeout(() => clearInterval(intervalId), 5000); // 5 saniyədən sonra dayandırılır

// Səhvə yol açan nümunə
function showMessage() {
  console.log('Mesaj');
}

setTimeout(showMessage(), 1000); // Səhv: undefined

// Düzgün yol
setTimeout(showMessage, 1000); // 1 saniyə sonra: Mesaj

// setTimeout ilə tək icra
function singleMessage() {
  console.log('Tək mesaj');
}

setTimeout(singleMessage, 2000); // 2 saniyə sonra: Tək mesaj

// setInterval ilə təkrar icra
function repeatedMessage() {
  console.log('Təkrarlanan mesaj');
}

const intervalId = setInterval(repeatedMessage, 1000);
setTimeout(() => clearInterval(intervalId), 5000); // 5 saniyədən sonra dayandırılır

